1	import type { WSClient, PersonaData } from "./types.js";
2	import { AgentSession } from "./ai-client.js";
3	import { chatStore } from "./chat-store.js";
4	
5	// Session manages a single chat conversation with a long-lived agent
6	export class Session {
7	  public readonly chatId: string;
8	  private subscribers: Set<WSClient> = new Set();
9	  private agentSession: AgentSession;
10	  private isListening = false;
11	
12	  // Per-session persona and uploaded file tracking
13	  private persona: PersonaData | undefined;
14	  private uploadedFiles: string[] = [];
15	
16	  constructor(chatId: string) {
17	    this.chatId = chatId;
18	    this.agentSession = AgentSession.create();
19	  }
20	
21	  /**
22	   * Store persona data for this session. Called when the client sends
23	   * persona information with a chat message.
24	   */
25	  setPersona(persona: PersonaData) {
26	    this.persona = persona;
27	  }
28	
29	  /**
30	   * Register an uploaded file path so the agent knows it can Read it.
31	   */
32	  addUploadedFile(filePath: string) {
33	    if (!this.uploadedFiles.includes(filePath)) {
34	      this.uploadedFiles.push(filePath);
35	    }
36	  }
37	
38	  // Start listening to agent output (call once)
39	  private async startListening() {
40	    if (this.isListening) return;
41	    this.isListening = true;
42	
43	    try {
44	      for await (const message of this.agentSession.getOutputStream()) {
45	        this.handleSDKMessage(message);
46	      }
47	    } catch (error) {
48	      console.error(`Error in session ${this.chatId}:`, error);
49	      this.broadcastError((error as Error).message);
50	    }
51	  }
52	
53	  /**
54	   * Send a user message to the agent.
55	   *
56	   * If persona data is provided directly it takes precedence; otherwise
57	   * the stored persona (set via setPersona) is used.  Uploaded file
58	   * paths are always forwarded so the agent can reference them with Read.
59	   */
60	  sendMessage(content: string, persona?: PersonaData) {
61	    // Store user message
62	    chatStore.addMessage(this.chatId, {
63	      role: "user",
64	      content,
65	    });
66	
67	    // Broadcast user message to subscribers
68	    this.broadcast({
69	      type: "user_message",
70	      content,
71	      chatId: this.chatId,
72	    });
73	
74	    // Use provided persona or fall back to stored one
